#define RTOS_MUTEX_H

#include <stdint.h>

#define RTOS_WAIT_FOREVER   0xFFFFFFFFU
#define RTOS_NO_WAIT        0x00000000U

typedef void* Mutex_t;

typedef enum {
    RTOS_MUTEX_NORMAL    = 0,
    RTOS_MUTEX_RECURSIVE = 1
} RTOS_MutexType_t;

/* BREAKING: added name and type parameters */
Mutex_t RTOS_MutexCreate(const char *name, RTOS_MutexType_t type);
void    RTOS_MutexDelete(Mutex_t mutex);
int     RTOS_MutexLock(Mutex_t mutex, uint32_t timeout_ms);
void    RTOS_MutexUnlock(Mutex_t mutex);

/* Returns 1 if locked, 0 if free */
int     RTOS_MutexIsLocked(Mutex_t mutex);

#endif /* RTOS_MUTEX_H */

